function StructWonderlandGrid:StructWonderlandGrid()
    self.gridIndex = 0
    self.status = 0
    self.eventList = {}
end

function StructWonderlandGrid:CreateByPb(pb)
    self.gridIndex = pb.gridIndex
    self.status = pb.status
    self.eventList = {}
    for k,v in ipairs(pb.events) do
        local event =
        {
            eventId = v.eventId,
            type = v.type,
            moreInfo = v.moreInfo,
            scopes = v.scopes,
            refreshCount = v.refreshCount,
            fixedTreasure = v.fixedTreasure
        }
        table.insert(self.eventList,event)
    end
    self.influenced = pb.influenced

end

function StructWonderlandGrid:GetGridIndex()
    return self.gridIndex
end

function StructWonderlandGrid:GetStatus()
    return self.status
end
function StructWonderlandGrid:SetStatus(state)
     self.status = state
end

function StructWonderlandGrid:GetEventList()
    return self.eventList
end


function StructWonderlandGrid:SetLayerIndex(layerIndex)
    self.layerIndex = layerIndex
end

function StructWonderlandGrid:GetLayerIndex()
    return self.layerIndex
end

function StructWonderlandGrid:GetInfluenced()
